INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00252', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '數字詞在詞彙中有實數和虛數兩種意涵，下列詞彙中的「三」字，作「實數」解釋的是那一選項？', '["退避「三」舍", "「三」心二意", "垂涎「三」尺", "拼命「三」郎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00253', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '下列文句「」中的成語，何者運用最恰當？', '["投機者為達目的不擇手段，「曲直分明」，終無法行之長遠", "他待人親切隨和，行為處事又有原則，真可謂「和而不同」", "今天下午舉行萬安演習，市區頓時「萬人空巷」，不見人車", "股票市場變化詭譎，民眾投資獲利「如履薄冰」，大幅縮水"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00254', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '阿康與小靖絕交後，寫了一封信，試圖挽回兩人的情誼。下列文句都出自阿康的信，「」中的成語， 使用最正確的是：', '["我們共同享有的回憶至今如「黃粱一夢」，難以忘懷", "只怪我太自以為是，又目空一切，經常「妄自菲薄」", "由於善意造成的誤會，從此「割席分坐」，不再聯繫", "不知你是否也像我一樣，期待「風雨如晦」重修舊好"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00255', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '下列文句「」中的成語，何者使用正確？', '["網路上的這些消息早已成為「明日黃花」，毫無新聞價值", "這條商業街已經沒落，即便是假日也是「人丁單薄」毫無生機", "他是個「目不暇給」的短視近利者，沒有宏觀與全盤規劃的視野", "這次的展覽獲得來自各界的「溢美之詞」，對參展者來說可謂非常成功"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00256', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '下列文句，何者詞語的使用不恰當？', '["生命中有許多事往往不在我們的掌握之中，但今天我終於一償夙願了", "比賽時間到了，球員沒有進場，裁判臉色鐵青，現場的氣氛莊嚴肅穆", "敵機來襲時，天空轟轟作響，每當巨彈墜地，則火光迸裂，煙霧迷漫", "那場席捲全球的經濟危機，讓許多人損失慘重，他也因此而一蹶不振"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00257', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '「我曾見過二人下棋，□□是坐著，神情瀟灑，望之如神仙中人，□□棋勢吃緊，兩人都站起來了， 劍拔弩張，如鬥鵪鶉，最後到了生死關頭，兩個人跳到桌上去了！」 根據上文，從詞語應用與文意邏輯連貫的角度，□□處依序最適合填入的選項是：', '["除非／否則", "起先／俄而", "主要／恐怕", "有的／另外"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00258', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '下列選項，何者沒有冗贅的字詞？', '["假使你倘若不願意付出努力，再多警告提醒也沒用", "畢竟你終歸要面對挑戰，何不從現在當下開始準備", "是你的督促鼓舞我成長，讓我決心追求高遠的目標", "你要多留心注意機會的到來，然後更積極主動把握"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00259', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '生活中有各種人際關係，因而產生不同的「稱謂」。下列有關「稱謂」的運用，正確的選項是：', '["稱呼自己太太的兄弟，可以用小叔", "對他人稱呼自己的父親，使用尊翁", "稱呼老師的太太為師母，稱呼老師的先生為師父", "稱呼父親的老師或老師的老師為太老師、太先生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00260', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '王大明用傳統直式信封寄信給父親王啟英先生，信封繕寫下列敘述何者正確？', '["緘封詞要寫在框右欄", "受信人地址應寫在框左欄", "框內欄寫「王啟英先生 收啟」", "信封的緘封詞應該要用「謹緘」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00261', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-34c7f7f6', 'sub-aboriginal-57f41407-02', NULL, 'single_choice', '畢業學生寫信向老師請安、拜年並報告近況，結尾敬辭正確的是：', '["恭請 道安", "即詢 大安", "順問 學安", "敬祝 捷安"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:15+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
